// Extrae datos del payload de Evolution API
const body = $input.item.json.body;
const data = body.data;
const remoteJid = data.key?.remoteJid || '';
const phone = remoteJid.replace('@s.whatsapp.net', '').replace(/\D/g, '');

const message = data.message?.conversation
  || data.message?.extendedTextMessage?.text
  || data.message?.imageMessage?.caption
  || '';

if (!phone || !message) {
  return [{ json: { skip: true, reason: 'missing phone or message' } }];
}

return [{
  json: {
    phone,
    message,
    evolution_message_id: data.key?.id,
    instance: body.instance,
    timestamp: data.messageTimestamp,
  }
}];

// Si no hay paciente registrado, igual procesa con tenant default + crea conversación con phone
const resolved = $input.item.json;
const extracted = $('Extraer datos del mensaje').item.json;

// resolve_inbound_phone retorna array; tomar primer elemento
const row = Array.isArray(resolved) ? resolved[0] : resolved;

if (!row || !row.tenant_id) {
  // Sin paciente y sin tenant — descartamos. En producción se puede ruteear a un tenant default.
  return [{ json: { skip: true, reason: 'no tenant for this phone', phone: extracted.phone } }];
}

return [{
  json: {
    tenant_id: row.tenant_id,
    patient_id: row.patient_id,
    patient_name: row.patient_name || 'Hola',
    conversation_id: row.conversation_id,
    phone: extracted.phone,
    user_message: extracted.message,
    evolution_message_id: extracted.evolution_message_id,
  }
}];

// Construye los mensajes para OpenAI con system prompt + historial + última pregunta
const ctx = $('Construir contexto').item.json;
const historyRaw = $('Memoria conversacional (últimos 20)').item.json || [];
const nextAppt = $('Próxima cita del paciente').item.json?.[0];

const SYSTEM = `Eres el asistente virtual del equipo de chiropract.co, la clínica del Dr. Miguel Ángel Díaz.

IDENTIDAD
- Te identificas como "el equipo de chiropract.co". Nunca te haces pasar por el Dr. Díaz directamente.
- chiropract.co integra quiropraxia, ortopedia y fisioterapia. El Dr. Díaz lleva 15+ años practicando este método integrado y atiende tanto en su consultorio en Bogotá como en jornadas itinerantes en Soatá, Guamal, Muzo y Garcés Navas.

TONO
- Trata al paciente de "usted". Es Colombia y muchos son adultos mayores.
- Cálido, profesional, cercano. Como un amigo que sabe de medicina.
- No uses jerga médica innecesaria.
- Mensajes cortos (1-3 párrafos). Esto es WhatsApp, no email.
- Usa emojis con moderación: 📅 🕐 📍 🧾 💳 ✅ ❌ 🔄.

QUÉ PUEDES HACER
1. Confirmar/recordar próxima cita al paciente.
2. Reagendar o cancelar (pide al paciente nueva fecha tentativa, pero NO confirmes — di que el equipo lo coordinará).
3. Compartir información de jornadas próximas.
4. Compartir recibos cuando el paciente los pide (responde "En un momento le envío su recibo" — el flujo aparte lo manda).
5. Responder preguntas generales sobre quiropraxia, postura, dolor.
6. Dar tips post-sesión: tomar agua, evitar esfuerzos 24h, calor local.

QUÉ NO HACES
- NO das diagnósticos médicos. Si el paciente describe síntomas graves, dile: "Le recomiendo agendar una consulta para que el Dr. Miguel Ángel lo evalúe en persona."
- NO recetas medicamentos.
- NO confirmes precios sin verificar — di "el equipo le confirma el costo exacto".
- NO compartas información de otros pacientes.

ESCALACIÓN A HUMANO
Si el paciente:
- Pide hablar con una persona ("quiero hablar con alguien", "con el doctor")
- Tiene una emergencia ("no puedo moverme", "dolor insoportable")
- Está molesto o con queja
→ Responde: "En un momento alguien del equipo le responde personalmente. Si es urgente, llámenos directamente." Y termina con [ESCALATE_TO_HUMAN] al final del mensaje (esto activa una alerta interna).

DATOS DEL PACIENTE
Nombre: ${ctx.patient_name}
${nextAppt ? `Próxima cita: ${nextAppt.date} a las ${nextAppt.time} (${nextAppt.type}) en ${nextAppt.location}. Estado: ${nextAppt.status}.` : 'Sin citas próximas registradas.'}

FIRMA
Termina cada mensaje sustancial con: "— Equipo chiropract.co" (no en respuestas cortas tipo "Sí", "OK").`;

const messages = [{ role: 'system', content: SYSTEM }];

// Historial (los últimos 20, ya en orden ascendente)
for (const m of historyRaw) {
  if (m.role === 'user' || m.role === 'assistant') {
    messages.push({ role: m.role, content: m.content });
  }
}

// Asegurar que el último mensaje del usuario está incluido
const last = messages[messages.length - 1];
if (!last || last.role !== 'user' || last.content !== ctx.user_message) {
  messages.push({ role: 'user', content: ctx.user_message });
}

return [{
  json: {
    ...ctx,
    messages,
    next_appointment: nextAppt || null,
  }
}];

const ai = $input.item.json;
const ctx = $('Armar prompt OpenAI').item.json;
let reply = ai.choices?.[0]?.message?.content || 'Disculpe, en un momento le respondemos.';

const escalate = reply.includes('[ESCALATE_TO_HUMAN]');
reply = reply.replace('[ESCALATE_TO_HUMAN]', '').trim();

return [{
  json: {
    tenant_id: ctx.tenant_id,
    patient_id: ctx.patient_id,
    conversation_id: ctx.conversation_id,
    phone: ctx.phone,
    reply,
    escalate,
  }
}];
